script.text:
      /* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    gia_nt2_sl: '[gia_nt2]:=([gia_nt2] == 0 ? ([so_luong] != 0 ? ([tien_nt2]/[so_luong]) : 0) : [gia_nt2])',
    gia2_sl: '[gia2]:=([gia2] == 0 ? ([so_luong] != 0 ? ([tien2]/[so_luong]) : 0) : [gia2])',

    gia_ban: '[gia_ban]:=[gia_ban_nt]*[$ty_gia]',
    gia2: '[gia2]:=[gia_nt2]*[$ty_gia]',

    tien_nt2: '[tien_nt2]:=[so_luong]*[gia_nt2]',
    tien2_tg: '[tien2]:=[tien_nt2]*[$ty_gia]',
    tien2_sl: '[tien2]:=[so_luong]*[gia2]',
    ck: '[ck]:=[ck_nt]*[$ty_gia]',
    thue_nt: '[thue_nt]:=([tien_nt2] - [ck_nt])*[thue_suat]/100',
    thue_tg: '[thue]:=[thue_nt]*[$ty_gia]',
    thue: '[thue]:=([tien2] - [ck])*[thue_suat]/100',

    t_so_luong: ['t_so_luong', 'so_luong'],
    t_tien_nt2: ['t_tien_nt2', 'tien_nt2'],
    t_tien2: ['t_tien2', 'tien2'],
    t_ck_nt: ['t_ck_nt', 'ck_nt'],
    t_ck: ['t_ck', 'ck'],
    t_thue_nt: ['t_thue_nt', 'thue_nt'],
    t_thue: ['t_thue', 'thue'],

    t_tt_nt: '[t_tt_nt]:=[t_tien_nt2] - [t_ck_nt]+[t_thue_nt]',
    t_tt: '[t_tt]:=[t_tien2] - [t_ck]+[t_thue]'
  };
  g.$h = [['voucherCode', 'String', g._voucherCode], 'ma_kh', 'ngay_lct', 'ma_tt', 'ma_nt', 'ma_gd', 'ma_dvcs'];
  udf$Detail$(g);
}
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
}
function onChange$GridVoucherDetail$Item(o) {o.grid.request(o, 'Item', 'Item', ['ma_vt', 'ma_kho', 'so_luong'], o.grid.$h, true);}
function onChange$GridVoucherDetail$UOM(o) {o.grid.request(o, 'UOM', 'UOM', ['ma_vt', 'ma_kho', 'dvt', 'so_luong'], o.grid.$h, true);}
function onChange$GridVoucherDetail$Site(o) {o.grid.request(o, 'Site', 'Site', ['ma_vt', 'ma_kho', 'dvt', 'so_luong', 'he_so'], o.grid.$h, true);}
function onChange$GridVoucherDetail$Quantity(o) {o.grid.request(o, 'Quantity', 'Quantity', ['ma_vt', 'ma_kho', 'dvt', 'so_luong', 'he_so'], o.grid.$h);}
function onChange$GridVoucherDetail$TaxCode(o) {o.grid.request(o, 'GetTaxRate', 'GetTaxRate', ['ma_thue']);}
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'gia_nt2':
      g.validExpression(o, [g.$a.gia2, g.$a.tien_nt2, g.$a.tien2_tg, g.$a.thue_nt, g.$a.thue_tg], [g.$a.t_tien_nt2, g.$a.t_tien2, g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'gia2':
      g.validExpression(o, [g.$a.tien2_sl, g.$a.thue], [g.$a.t_tien2, g.$a.t_thue], [g.$a.t_tt]);
      break;
    case 'tien_nt2':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_nt2_sl, g.$a.gia2]);
      g.validExpression(o, [g.$a.tien2_tg, g.$a.thue_nt, g.$a.thue_tg], [g.$a.t_tien_nt2, g.$a.t_tien2, g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'tien2':
      if (f._calPrice) g.validExpression(o, [g.$a.gia2_sl]);
      g.validExpression(o, [g.$a.thue], [g.$a.t_tien2, g.$a.t_thue], [g.$a.t_tt]);
      break;
    case 'ck_nt':
      g.validExpression(o, [g.$a.ck, g.$a.thue_nt, g.$a.thue_tg], [g.$a.t_ck_nt, g.$a.t_ck, g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'ck':
      g.validExpression(o, [g.$a.thue], [g.$a.t_ck, g.$a.t_thue], [g.$a.t_tt]);
      break;
    case 'thue_nt':
      g.validExpression(o, [g.$a.thue_tg], [g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'thue':
      g.validExpression(o, null, [g.$a.t_thue], [g.$a.t_tt]);
      break;
    default:
      break;
  }
}
/* </flatten> */
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {&ScriptCheckGridAction;
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'Check':
      if (!(g.validRowExpression('so_luong', '[so_luong] != 0'))) break;
      break;
    case 'Retrieve':
      if (f._action == 'View') break;
      if (!f.validFields('ma_kh, ngay_lct')) break;
      switch (e.type.Value) {
        case '10':
          if (f.getItemValue('loai_ct') != '2') g.showForm('SOBlanketFilter');
          break;
        case '30':
          g.showForm('SOQuotationFilter');
          break;
        default:
          break;
        }
      break;
    case 'Copying':
      set$Voucher$EmptyExternalField(g, 'sl_xuat, sl_hd, stt_rec_hd, stt_rec0hd, stt_rec_bg, stt_rec0bg');
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'Item':
      var v = (result[20].Value == '' ? 'false' : 'true');
      g.setItemGridBehavior(o, [
        ['ma_kho', result[0].Value, '', true],
        ['dvt', result[3].Value, '', true],
        ['he_so', result[4].Value, null, null],
        ['gia_ban_nt', result[5].Value, null, null],
        ['gia_nt2', result[6].Value, null, true],
        ['ck_nt', result[7].Value, null, true],
        ['ma_thue', [result[20].Value, v], '', null],
        ['thue_suat', [result[21].Value, v], null, null]
      ]);
      on$GridVoucherDetail$SalesPriceChange(o, g, f);
      g.live(o, 'dvt');
      break;
    case 'GetTaxRate':
      if (g._getItemValue(o.row, g._getColumnOrder('thue_suat')) != result[0].value) {
        g.setItemGridBehavior(o, [['thue_suat', result[0].Value, '', false]]);
        g.validExpression(o, [g.$a.thue_nt, g.$a.thue_tg], [g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt], 'thue_nt');
      }
      break;
    case 'UOM':
      on$GridVoucherDetail$SalesPriceResponse(result, o, g, f, true);
      break;
    case 'Site':
      on$GridVoucherDetail$SalesPriceResponse(result, o, g, f);
      break;
    case 'Quantity':
      on$GridVoucherDetail$SalesPriceResponse(result, o, g, f);
      g.validExpression(o, null, [g.$a.t_so_luong], null, 'gia_nt2');
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$RowChange(g, f) {
  g.executeAggregate([g.$a.t_so_luong, g.$a.t_tien_nt2, g.$a.t_tien2, g.$a.t_ck_nt, g.$a.t_ck, g.$a.t_thue_nt, g.$a.t_thue]);
  f.executeExpression([g.$a.t_tt_nt, g.$a.t_tt]);
}
function on$GridVoucherDetail$SalesPriceResponse(result, o, g, f, force) {
  var a = [['gia_nt2', result[2].Value, null, true], ['ck_nt', result[3].Value, null, true]], v = true;
  if (force) {
    v = false;
    Array.add(a, ['he_so', result[0].Value, null, true]);
    Array.add(a, ['gia_ban_nt', result[1].Value, null, true]);
  }
  g.setItemGridBehavior(o, a);
  on$GridVoucherDetail$SalesPriceChange(o, g, f, v);
}
function on$GridVoucherDetail$SalesPriceChange(o, g, f, force) {
  if (force) g.executeExpression(o, [g.$a.gia2, g.$a.ck, g.$a.tien_nt2, g.$a.tien2_sl, g.$a.thue_nt, g.$a.thue]);
    else g.executeExpression(o, [g.$a.gia_ban, g.$a.gia2, g.$a.ck, g.$a.tien_nt2, g.$a.tien2_sl, g.$a.thue_nt, g.$a.thue]);
  g.executeAggregate([g.$a.t_tien_nt2, g.$a.t_tien2, g.$a.t_ck_nt, g.$a.t_ck, g.$a.t_thue_nt, g.$a.t_thue]);
  f.executeExpression([g.$a.t_tt_nt, g.$a.t_tt]);
}
/* </flatten> */
      &ScriptInsertRetrieveItems;
